```go
package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases – набор edge‑case‑ов для метода
// Order.CalculateTotal().  В проекте уже есть тесты
//   - TestUnitOrderCalculateTotalEmpty
//   - TestUnitOrderCalculateTotalSingleItem
//   - TestUnitOrderCalculateTotalLargeOrder
//   - TestUnitOrderCalculateTotalFloatPrecision
//   - TestUnitOrderCalculateTotalVariousItemCounts
//   - TestUnitOrderCalculateTotalNilItems
//   - TestUnitOrderCalculateTotalMixedPrices
//   - TestUnitOrderCalculateTotalOverwritesPrevious
// поэтому в этом тесте мы покрываем сценарии, которые пока не проверяются:
//   1. Сумма, приводящая к +Inf (очень большой price)
//   2. Сумма, содержащая NaN (price = NaN)
//   3. Очень маленькая цена при огромном количестве (проверка точности)
//   4. Отрицательная цена (корректно суммируется, хотя валидация должна её отсеять)
//   5. Максимальное значение int для quantity (не переполняет float64)
//   6. Смешанный набор нулевых и положительных цен (проверка, что нули не влияют)
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Parallel()

	type tc struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantIsInf   bool // true → ожидаем +Inf
		wantIsNaN   bool // true → ожидаем NaN
		tolerance   float64
	}
	cases := []tc{
		{
			name: "very_large_price_overflows_to_inf",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: math.MaxFloat64},
			},
			wantTotal: math.Inf(1),
			wantIsInf: true,
		},
		{
			name: "price_nan_propagates",
			items: []OrderItem{
				{ProductID: 2, Quantity: 1, Price: math.NaN()},
			},
			wantTotal: math.NaN(),
			wantIsNaN: true,
		},
		{
			name: "tiny_price_large_quantity",
			// 0.0000001 * 1 000 000 000 = 100.0
			items: []OrderItem{
				{ProductID: 3, Quantity: 1_000_000_000, Price: 0.0000001},
			},
			wantTotal: 100.0,
			tolerance: 1e-9,
		},
		{
			name: "negative_price_is_added_as_negative",
			items: []OrderItem{
				{ProductID: 4, Quantity: 3, Price: -10.0},
				{ProductID: 5, Quantity: 2, Price: 25.0},
			},
			// (-10 * 3) + (25 * 2) = -30 + 50 = 20
			wantTotal: 20.0,
			tolerance: 1e-9,
		},
		{
			name: "max_int_quantity_without_overflow",
			items: []OrderItem{
				{ProductID: 6, Quantity: math.MaxInt32, Price: 1.0},
			},
			// MaxInt32 * 1.0 = 2147483647
			wantTotal: float64(math.MaxInt32),
			tolerance: 0.0,
		},
		{
			name: "mixed_zero_and_positive_prices",
			items: []OrderItem{
				{ProductID: 7, Quantity: 5, Price: 0.0},
				{ProductID: 8, Quantity: 2, Price: 12.5},
				{ProductID: 9, Quantity: 3, Price: 0.0},
				{ProductID:10, Quantity: 1, Price: 7.25},
			},
			// (0*5)+(12.5*2)+(0*3)+(7.25*1) = 25 + 7.25 = 32.25
			wantTotal: 32.25,
			tolerance: 1e-9,
		},
	}

	for _, c := range cases {
		c := c // capture range variable
		t.Run(c.name, func(t *testing.T) {
			t.Parallel()

			o := &Order{
				Items: c.items,
			}
			o.CalculateTotal()

			if c.wantIsInf {
				if !math.IsInf(o.Total, +1) {
					t.Fatalf("expected Total to be +Inf, got %v", o.Total)
				}
				return
			}
			if c.wantIsNaN {
				if !math.IsNaN(o.Total) {
					t.Fatalf("expected Total to be NaN, got %v", o.Total)
				}
				return
			}
			// обычный сравнение с допуском
			if c.tolerance > 0 {
				if math.Abs(o.Total-c.wantTotal) > c.tolerance {
					t.Fatalf("Total = %v, want %v ±%v", o.Total, c.wantTotal, c.tolerance)
				}
			} else {
				if o.Total != c.wantTotal {
					t.Fatalf("Total = %v, want %v", o.Total, c.wantTotal)
				}
			}
		})
	}
}
```

### Что делает тест

| № | Сценарий | Почему он **не** дублирует существующие тесты |
|---|----------|

**Кратко:**  
`TestIntegrationProductSearch` падает из‑за того, что поиск в SQLite реализован через обычный `LIKE`‑оператор, а в тесте используется кириллический текст. В разных версиях SQLite (и даже в разных сборках Go‑sqlite‑driver) `LIKE` работает только с ASCII‑символами, а порядок возвращаемых строк зависит от того, как они были вставлены. Тест ожидает детерминированный набор/порядок результатов, поэтому иногда получает `nil`‑slice, пустой массив или строки в другом порядке – и падает.

Ниже перечислены типичные причины и конкретные шаги‑фиксы, которые можно применить **в коде репозитория** и **в самом тесте**.

---

## 1. Возможные причины падения

| № | Причина | Почему приводит к флейку |
|---|---------|--------------------------|
| 1 | **`LIKE` без указания колляции** – в SQLite `LIKE` по умолчанию чувствителен к регистру и работает только с ASCII. При поиске кириллической подстроки (`"латте"` → `"Латте"`) иногда возвращается `0` строк. | На некоторых платформах драйвер включает `PRAGMA case_sensitive_like=ON`, на других – `OFF`. Тест не контролирует эту настройку. |
| 2 | **Отсутствие `ORDER BY`** в запросе `SELECT … FROM products WHERE name LIKE ?` – SQLite может вернуть строки в произвольном порядке (обычно в порядке вставки, но при параллельных транзакциях/автокоммитах порядок меняется). Тест сравнивает с «ожидаемым» массивом, а полученный массив может быть перемешан. | При большом набором данных (10‑+ записей) порядок меняется между запусками. |
| 3 | **Неявный `COMMIT`** – в тесте используется `setupTestDB(t)` → `:memory:` DB, но если репозиторий открывает транзакцию и не фиксирует её до конца теста, часть вставленных строк может быть не видна в `SELECT`. | Иногда `INSERT` остаётся в открытой транзакции, а `Search` открывает новое соединение → видит только часть данных. |
| 4 | **Экранирование спецсимволов** – запрос `LIKE ?` получает строку `"%кофе%"`. Если в тесте используется `%` или `_` в поисковом запросе, они трактуются как шаблоны, а не как обычные символы. При разных версиях драйвера `%` может быть экранировано автоматически, а может – нет. | Тест `TestIntegrationProductSearchSpecialChars` (из расширенного набора) иногда падает, если `%` не экранируется. |
| 5 | **Разные кодировки** – в памяти SQLite хранит строки в UTF‑8, но если в тесте используется `[]byte` → `string` с неверным набором рангов, сравнение может дать `false`. | На Windows/Unix различия в `utf8`‑конвертации могут проявиться в редких запусках. |
| 6 | **Параллельный запуск тестов** – хотя каждый тест создаёт собственную БД, в CI иногда включён `go test -parallel N`. Если репозиторий использует глобальный `sql.DB` (singleton), два теста могут «делить» один in‑memory DB, и один из них «переписывает» данные другого. | Флейки появляются только при высокой нагрузке CI. |

---

## 2. Как исправить (код + тест)

### 2.1. Репозиторий – `sqlite/product.go`

```go
// file: internal/repository/sqlite/product.go
func (r *sqliteProductRepo) Search(ctx context.Context, query string, limit int) ([]*entity.Product, error) {
    // 1️⃣ Приводим запрос к нижнему регистру и используем COLLATE NOCASE.
    //    Это гарантирует, что поиск будет регистронезависимым и Unicode‑дружелюбным.
    // 2️⃣ Экранируем символы % и _ внутри query, чтобы они воспринимались как обычные.
    // 3️⃣ Добавляем ORDER BY id ASC, чтобы результат был детерминирован.
    // 4️⃣ Явно фиксируем транзакцию (если используется tx) – но в данном репо
    //    каждый запрос открывает новое соединение, поэтому достаточно PRAGMA.

    // Экранирование % и _
    esc := strings.NewReplacer(`%`, `\%`, `_`, `\_`).Replace(query)
    pattern := fmt.Sprintf("%%%s%%", esc)

    const stmt = `
        SELECT id, category_id, name, description, price, image_url, in_stock,
               created_at, updated_at
        FROM products
        WHERE name LIKE ? ESCAPE '\' COLLATE NOCASE
           OR description LIKE ? ESCAPE '\' COLLATE NOCASE
        ORDER BY id ASC
        LIMIT ?
    `
    rows, err := r.db.QueryContext(ctx, stmt, pattern, pattern, limit)
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    var out []*entity.Product
    for rows.Next() {
        p := new(entity.Product)
        if err := rows.Scan(&p.ID, &p.CategoryID, &p.Name, &p.Description,
            &p.Price, &p.ImageURL, &p.InStock, &p.CreatedAt, &p.UpdatedAt); err != nil {
            return nil, err
        }
        out = append(out, p)
    }
    return out, rows.Err()
}
```

**Что изменилось:**

| № | Изменение | Почему помогает |
|---|-----------|-----------------|
| 1 | `COLLATE NOCASE` | Делает поиск регистронезависимым и поддерживает Unicode‑символы (включая кириллицу). |
| 2 | `ESCAPE '\'` + экранирование `%`/`_` | Предотвращает «wildcard‑эффект» в тестах, где запрос содержит специальные символы. |
| 3 | `ORDER BY id ASC` | Гарантирует одинаковый порядок независимо от того, как SQLite хранит строки. |
| 4 | Явный `pattern := fmt.Sprintf("%%%s%%", esc)` | Убирает двойные `%`‑потенциальные ошибки. |
| 5 | Добавлен `description LIKE …` (если тест ищет в описании) – теперь покрывается оба поля. |

> **Важно:** Если в проекте уже есть `PRAGMA case_sensitive_like=OFF` в `RunMigrations`, её можно оставить, но `COLLATE NOCASE` гарантирует нужный коллятор даже если pragma переопределён.

