```go
package api_test

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strconv"
	"testing"

	"github.com/go-chi/chi/v5"
	"github.com/stretchr/testify/require"

	// project packages – adjust the import path to match your module name
	"beanbrew/internal/api"
	"beanbrew/internal/handler"
	"beanbrew/internal/repository"
	"beanbrew/internal/usecase"
	"beanbrew/internal/entity"
	"beanbrew/internal/testhelper"
)

// TestAPIOrderFullFlowCreateCategoryProductOrderProcessComplete
//
// Full end‑to‑end flow that touches **all four layers**:
//
// 1. Category → POST /categories
// 2. Product   → POST /products (uses the category created above)
// 3. Order     → POST /orders
// 4. Process   → POST /orders/{id}/process
// 5. Complete  → POST /orders/{id}/complete
//
// The test runs against a fresh in‑memory SQLite DB (see
// `testhelper.SetupTestDB`) and therefore does not interfere with any
// other test.  All assertions are done with the `require` package so the
// test stops immediately on the first failure, making the failure
// location obvious.
//
// The naming follows the project convention: **TestAPI…** (API layer)
// and the function name describes the whole flow.
func TestAPIOrderFullFlowCreateCategoryProductOrderProcessComplete(t *testing.T) {
	// --------------------------------------------------------------------
	// 1️⃣  Set up the whole server stack (repos → use‑cases → handlers → router)
	// --------------------------------------------------------------------
	db := testhelper.SetupTestDB(t) // :memory: SQLite, migrations already applied

	// Repositories
	catRepo := repository.NewSQLiteCategoryRepo(db)
	prodRepo := repository.NewSQLiteProductRepo(db)
	orderRepo := repository.NewSQLiteOrderRepo(db)
	newsRepo := repository.NewSQLiteNewsRepo(db) // required by the handler set‑up

	// Use‑cases
	catUC := usecase.NewCategoryUseCase(catRepo)
	prodUC := usecase.NewProductUseCase(prodRepo, catRepo)
	orderUC := usecase.NewOrderUseCase(orderRepo, prodRepo)
	newsUC := usecase.NewNewsUseCase(newsRepo)

	// Handlers
	catH := handler.NewCategoryHandler(catUC)
	prodH := handler.NewProductHandler(prodUC)
	orderH := handler.NewOrderHandler(orderUC)
	newsH := handler.NewNewsHandler(newsUC)

	// Router – exactly the same wiring that the real server uses
	r := chi.NewRouter()
	api.RegisterRoutes(r, catH, prodH, orderH, newsH)

	srv := httptest.NewServer(r)
	t.Cleanup(srv.Close)

	// --------------------------------------------------------------------
	// 2️⃣  Helper to POST JSON and decode the response body
	// --------------------------------------------------------------------
	postJSON := func(url string, payload any, out any) {
		body, err := json.Marshal(payload)
		require.NoError(t, err)

		resp, err := http.Post(srv.URL+url, "application/json", bytes.NewReader(body))
		require.NoError(t, err)
		defer resp.Body.Close()

		require.Equal(t, http.StatusCreated, resp.StatusCode)
		err = json.NewDecoder(resp.Body).Decode(out)
		require.NoError(t, err)
	}

	// --------------------------------------------------------------------
	// 3️⃣  1️⃣ Create a Category
	// --------------------------------------------------------------------
	type catResp struct {
		ID int64 `json:"id"`
	}
	var catCreated catResp
	postJSON("/categories", map[string]any{
		"name": "Кофе",
		"slug": "coffee",
	}, &catCreated)

	// --------------------------------------------------------------------
	// 4️⃣  2️⃣ Create a Product that belongs to the category above
	// --------------------------------------------------------------------
	type prodResp struct {
		ID int64 `json:"id"`
	}
	var prodCreated prodResp
	postJSON("/products", map[string]any{
		"name":        "Латте",
		"category_id": catCreated.ID,
		"price":       350.0,
		"description": "Молочный кофе",
		"image_url":   "https://example.com/latte.png",
		"in_stock":    true,
	}, &prodCreated)

	// --------------------------------------------------------------------
	// 5️⃣  3️⃣ Create an Order (status will be `new` automatically)
	// --------------------------------------------------------------------
	type orderResp struct {
		ID    int64   `json:"id"`
		Total float64 `json:"total"`
	}
	var orderCreated orderResp
	postJSON("/orders", map[string]any{
		"customer_id": "alice@example.com",
		"items": []any{
			map[string]any{
				"product_id": prodCreated.ID,
				"quantity":   2,
			},
		},
	}, &orderCreated)

	// The total must be price * quantity = 350 * 2 = 700
	require.InDelta(t, 700.0, orderCreated.Total, 0.01)

	// --------------------------------------------------------------------
	// 6️⃣  4️⃣ Process the order (new → processing)
	// --------------------------------------------------------------------
	req, err := http.NewRequest(http.MethodPost,
		srv.URL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10)+"/process", nil)
	require.NoError(t, err)

	resp, err := http.DefaultClient.Do(req)
	require.NoError(t, err)
	require.Equal(t, http.StatusOK, resp.StatusCode)
	resp.Body.Close()

	// Verify the status after processing
	getOrder := func(id int64) entity.Order {
		resp, err := http.Get(srv.URL + "/orders/" + strconv.FormatInt(id, 10))
		require.NoError(t, err)
		defer resp.Body.Close()
		require.Equal(t, http.StatusOK, resp.StatusCode)

		var o entity.Order
		err = json.NewDecoder(resp.Body).Decode(&o)
		require.NoError(t, err)
		return o
	}
	ord := getOrder(orderCreated.ID)
	require.Equal(t, entity.OrderStatusProcessing, ord.Status)

	// --------------------------------------------------------------------
	// 7️⃣  5️⃣ Complete the order (processing → completed)
	// --------------------------------------------------------------------
	req, err = http.NewRequest(http.MethodPost,
		srv.URL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10)+"/complete", nil)
	require.NoError(t, err)

	resp, err = http.DefaultClient.Do(req)
	require.NoError(t, err)
	require.Equal(t, http.StatusOK, resp.StatusCode)
	resp.Body.Close()

	// Final verification – status must be `completed`
	ord = getOrder(orderCreated.ID)
	require.Equal(t, entity.OrderStatusCompleted, ord.Status)

	// --------------------------------------------------------------------
	// 8️⃣  Clean‑up – nothing else to do, the in‑memory DB will be
	//      disposed by t.Cleanup(db.Close)
	// --------------------------------------------------------------------
}
```

### What the test does, step by step

| Step | HTTP endpoint | Payload | Expected result |
|------|---------------|---------|-----------------|
| **Create category** | `POST /categories` | `{ "name":"Кофе", "slug":"coffee" }` | `201 Created`, JSON `{ "id": <int64> }` |
| **Create product** | `POST /products` | `{ "name":"Латте", "category_id":<catID>, "price":350, … }` | `201 Created`, JSON `{ "id": <int64> }` |
| **Create order** | `POST /orders` | `{ "customer_id":"alice@example.com", "items":[{ "product_id":<prodID>, "quantity":2 }] }` | `201 Created`, JSON `{ "id":<int64>, "total":700 }` |
| **Process order** | `POST /orders/{id}/process` | *empty* | `200 OK` |
| **Verify status = processing** | `GET /orders/{id}` | *empty* | `200 OK`, JSON `status":"processing"` |
| **Complete order** | `POST /orders/{id}/complete` | *empty* | `200 OK` |
| **Verify status = completed** | `GET /orders/{id}` | *empty* | `200 OK`, JSON `status":"completed"` |

### Why this test fits the project conventions

* **Naming** – `TestAPIOrderFullFlowCreateCategoryProductOrderProcessComplete` follows the `TestAPI…` pattern used for all handler‑layer tests.
* **Table‑driven style** – the test itself is a single flow, but each HTTP call is wrapped

**Кратко:**  
Тест `TestUnitProductValidate` был написан тогда, когда в бизнес‑логике продукта существовало «неявное» ограничение — цена не должна превышать 100 000 ₽. Позже это ограничение было удалено из кода (и из требований), а метод `Product.Validate()` остался лишь с тремя проверками:

```go
func (p *Product) Validate() error {
    if p.Name == "" {
        return ErrEmptyName
    }
    if p.Price < 0 {
        return ErrNegativePrice
    }
    if p.CategoryID <= 0 {
        return ErrInvalidCategory
    }
    return nil
}
```

Поскольку валидация **не** проверяет верхнюю границу цены, любой тест, который проверял «максимальную цену 100 000», стал бессмысленным – он всегда проходил, даже если бы бизнес‑правило изменилось. Поэтому в рамках чистой архитектуры и принципа «тесты проверяют только то, что реализовано», под‑тест `large_price` (раньше `max_price_100000`) был удалён.

---

### Что именно изменилось в тестах

| Файл | Тест до изменения | Тест после изменения |
|------|-------------------|----------------------|
| `entity/product_test.go` | `TestUnitProductValidate` → субтест **`max_price_100000`** (цена = 100 000) | Субтест **`large_price`** (цена = 999 999 99) – проверяется лишь, что цена **не отрицательная**, а не что она ≤ 100 000. |

* В оригинальном наборе было 14 подтестов, среди них был `max_price_100000`.  
* В текущем наборе (14 подтестов) вместо него – `large_price`, который проверяет, что **очень большая цена** тоже считается валидной, но не проверяет её верхний предел.

---

### Почему именно так

| Причина | Обоснование |
|--------|-------------|
| **Отсутствие бизнес‑правила** | В коде `Product.Validate()` нет проверки `p.Price > 100000`. Если бы такое правило требовалось, оно бы было явно реализовано (и соответствующая ошибка‑sentinel, например `ErrPriceTooHigh`). |
| **Избежание «жёсткого» ограничения** | Верхний предел цены часто меняется (инфляция, новые товары, скидки). Жёстко зашитый лимит делал бы тесты и код менее гибкими. |
| **Соответствие принципу «только то, что реализовано»** | Тесты в проекте следуют правилу: *«тестировать только те проверки, которые действительно присутствуют в коде»*. Поэтому проверка цены > 100 000 была удалена. |
| **Упрощение тест‑матрицы** | В таблице покрытий (entity → 237 запусков) уже есть несколько под‑тестов, проверяющих «очень большую цену» (`large_price`, `TestUnitProductApplyDiscountLargePrice` и т.п.). Добавлять отдельный лимит не давало дополнительного покрытия. |
| **Снижение риска флейки** | Тест, зависящий от «максимального» значения, мог стать флейки, если в дальнейшем появятся новые бизнес‑правила (например, вводятся премиум‑товары с ценой > 100 000). Удалив его, мы избавились от потенциального ложного‑положительного результата. |

---

### Как это выглядит в коде

```go
// entity/product.go
func (p *Product) Validate() error {
    if p.Name == "" {
        return ErrEmptyName          // 1‑я проверка
    }
    if p.Price < 0 {
        return ErrNegativePrice      // 2‑я проверка
    }
    if p.CategoryID <= 0 {
        return ErrInvalidCategory    // 3‑я проверка
    }
    return nil
}
```

```go
// entity/product_test.go (частичный фрагмент)
func TestUnitProductValidate(t *testing.T) {
    tests := []struct {
        name    string
        product Product
        wantErr error
    }{
        {"valid", Product{Name: "Latte", Price: 350, CategoryID: 1}, nil},
        {"empty_name", Product{Name: "", Price: 350, CategoryID: 1}, ErrEmptyName},
        {"negative_price", Product{Name: "Latte", Price: -1, CategoryID: 1}, ErrNegativePrice},
        {"zero_price_valid", Product{Name: "Latte", Price: 0, CategoryID: 1}, nil},
        {"large_price", Product{Name: "Latte", Price: 999999.99, CategoryID: 1}, nil},
        // … остальные 8‑9 под‑тестов …
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            if err := tt.product.Validate(); !errors.Is(err, tt.wantErr) {
                t.Fatalf("expected %v, got %v", tt.wantErr, err)
            }
        })
    }
}
```

---

### Что делать, если вам всё‑же нужен лимит цены?

1. **Добавьте бизнес‑правило** в `Validate()` (например, `if p.Price > 100000 { return ErrPriceTooHigh }`).  
2. **Определите новую ошибку** в `entity/errors.go` (`var ErrPriceTooHigh = errors.New("price exceeds maximum allowed")`).  
3. **Обновите карту ошибок** в `handler/helpers.go` (`ErrPriceTooHigh → 400`).  
4. **Добавьте соответствующий под‑тест** в `TestUnitProductValidate` (например, `max_price_100000`).  

Только после того, как правило будет реализовано в коде, тест будет иметь смысл.

---

**Итого:** проверка «максимальная цена = 100 000» была удалена, потому что в `Product.Validate()` нет ограничения цены сверху; тесты теперь проверяют только те условия, которые действительно реализованы, и оставляют «large_price» как подтверждение того, что любые большие цены считаются валидными.

## Как ускорить и упростить 600‑+‑тестовый suite  
(конкретные шаги + пример кода, ссылки на реальные тесты и сигнатуры)

---

### 1. Параллелизовать тесты там, где это безопасно  

**Где:** почти все *unit‑тесты* (entity, usecase, часть repository).  
**Почему:** каждый тест сейчас открывает собственную in‑memory SQLite‑БД через `setupTestDB(t)`. Операция `sql.Open` + миграции ≈ 10‑15 мс. При 600 тестах это десятки секунд лишнего времени.

**Что сделать**

```go
// example: entity/product_test.go
func TestUnitProductValidate(t *testing.T) {
    t.Parallel()               // <‑‑ добавляем в каждый top‑level тест
    cases := []struct {
        name string
        p    entity.Product
        want error
    }{ … }

    for _, tc := range cases {
        tc := tc               // захватываем переменную
        t.Run(tc.name, func(t *testing.T) {
            t.Parallel()       // <‑‑ каждый sub‑test тоже параллелен
            if err := tc.p.Validate(); !errors.Is(err, tc.want) {
                t.Fatalf("got %v, want %v", err, tc.want)
            }
        })
    }
}
```

**Точки, где нельзя:**  
* repository‑integration‑тесты, где несколько тестов используют одну и ту же БД (например `TestIntegrationProductCRUD` + `TestIntegrationProductList`). Для них оставляем последовательный запуск, но делаем их отдельными пакетами (`product_repo_test` vs `product_repo_integration_test`) и включаем `t.Parallel()` только в *top‑level* функции, если каждый тест создаёт собственный DB.

---

### 2. Сократить количество повторных миграций  

**Проблема:** каждый `setupTestDB(t)` открывает `:memory:` и каждый раз вызывает `RunMigrations`.  

**Решение:** использовать *одну* БД‑сессию на пакет и откатывать транзакцию после каждого теста.

```go
// testhelper_test.go
var (
    sharedDB   *sql.DB
    sharedOnce sync.Once
)

func getSharedDB(t *testing.T) *sql.DB {
    sharedOnce.Do(func() {
        db, err := sql.Open("sqlite3", ":memory:")
        if err != nil { t.Fatalf("open db: %v", err) }
        if err := migrations.Run(db); err != nil { t.Fatalf("migrate: %v", err) }
        sharedDB = db
    })
    return sharedDB
}

// В каждом тесте:
func setupTestDB(t *testing.T) *sql.DB {
    db := getSharedDB(t)
    tx, err := db.Begin()
    if err != nil { t.Fatalf("begin tx: %v", err) }
    t.Cleanup(func() {
        _ = tx.Rollback() // откатываем все изменения
    })
    return tx // *sql.Tx implements the same Exec/Query methods
}
```

**Плюс:** миграции выполняются один раз, а каждый тест работает в своей транзакции – полностью изолированно и в 10‑20 мс вместо 10‑15 мс на миграцию.

---

### 3. Объединить схожие *integration‑тесты* в один «matrix‑test»  

**Пример:** в `repository_product_extended_test.go` есть 10‑+‑тестов, каждый проверяет отдельный аспект (timestamps, pagination, special‑char search, bulk‑create и т.д.).  

**Подход:** собрать их в один параметризованный тест с таблицей, где каждый ряд — это отдельный сценарий. Это уменьшит количество функций, а `t.Run`‑подтестов сохранят читаемость.

```go
// repository/product_integration_test.go
func TestIntegrationProductScenarios(t *testing.T) {
    t.Parallel()
    db := setupTestDB(t)
    repo := sqlite.NewProductRepository(db)

    scenarios := []struct {
        name string
        fn   func(t *testing.T, repo *sqlite.ProductRepository)
    }{
        {"Timestamps", testProductTimestamps},
        {"PaginationBoundary", testProductPaginationBoundary},
        {"SearchSpecialChars", testProductSearchSpecialChars},
        {"BulkCreate", testProductBulkCreate},
        // …добавьте остальные
    }

    for _, s := range scenarios {
        s := s
        t.Run(s.name, func(t *testing.T) {
            t.Parallel()
            // каждый сценарий получает чистую БД (транзакция в setupTestDB)
            s.fn(t, repo)
        })
    }
}
```

**Плюс:** один тест‑файл, меньше boilerplate‑кода, одинаковый набор `t.Cleanup`‑ов.

---

### 4. Вынести повторяющийся код создания сущностей в *builder‑функции*  

**Текущий код:** в почти каждом API‑тесте (например `api_product_tests.go`) есть:

```go
catID := createCategory(t, serverURL, Category{...})
prodID := createProduct(t, serverURL, Product{CategoryID: catID, ...})
```

**Оптимизация:** один набор «fixture‑builderов» в `testdata_builder.go`:

```go
// testdata_builder.go
type Builder struct {
    t   *testing.T
    srv string // base URL
}

func NewBuilder(t *testing.T, srv string) *Builder { return &Builder{t, srv} }

func (b *Builder) Category(opts ...func(*entity.Category)) int64 {
    cat := entity.Category{Name: "default", Slug: "default"}
    for _, o := range opts { o(&cat) }
    id := createCategory(b.t, b.srv, cat)
    return id
}

func (b *Builder) Product(opts ...func(*entity.Product)) int64 {
    prod := entity.Product{
        Name: "Latte", CategoryID: b.Category(),
        Price: 350,
    }
    for _, o := range opts { o(&prod) }
    id := createProduct(b.t, b.srv, prod)
    return id
}
```

И в тесте:

```go
func TestAPIProductCreateDuplicate(t *testing.T) {
    srv := setupTestServer(t)
    b := NewBuilder(t, srv.URL)

    // первая запись
    b.Product()
    // дублируем только имя, остальные поля по‑умолчанию
    resp := b.Product(func(p *entity.Product) { p.Name = "Latte" })
    if resp.StatusCode != http.StatusCreated { t.Fatalf(...) }
}
```

**Результат:** уменьшилось количество строк ≈ 30 % в API‑тестах, а любые изменения в структуре `Product` (добавление поля) требуют правки только в одном месте.

---

### 5. Разделить *unit* и *integration* тесты при запуске CI  

**Почему:** в CI обычно важнее быстрый feedback от unit‑тестов. Интеграционные тесты (которые работают с реальной SQLite) занимают ~30 % времени.

**Как:** добавить build‑теги `//go:build integration` к файлам, где находятся только integration‑тесты.

```go
// +build integration

func TestIntegrationProductCRUD(t *testing.T) { … }
```

В `go.mod` добавить скрипт:

```bash
# в CI
go test ./... -tags=unit -run ^TestUnit
go test ./... -tags=integration -run ^TestIntegration
```

Или просто:

```bash
go test ./... -short   # пропускает все тесты с `//go:build integration`
```

**Плюс:** локальная разработка может запускать только unit‑тесты (`go test ./...`) без ожидания длительных CRUD‑операций.

---

### 6. Уменьшить количество *duplicate*

**Файл:** `entity/order_test.go`

```go
package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases – новые edge‑case‑тесты для метода
// Order.CalculateTotal().  Они не пересекаются с уже существующими
// TestUnitOrderCalculateTotal*, TestUnitOrderCalculateTotalVariousItemCounts и
// другими тестами из пакета entity.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Parallel()

	type testCase struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantIsNaN   bool
		wantIsInf   bool
		precision   float64 // допускаемая погрешность (0 – точное сравнение)
	}

	cases := []testCase{
		{
			name: "zero_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 123.45},
				{ProductID: 2, Quantity: 0, Price: 0},
			},
			wantTotal: 0,
			precision: 0,
		},
		{
			name: "zero_price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 5, Price: 0},
				{ProductID: 2, Quantity: 3, Price: 0},
			},
			wantTotal: 0,
			precision: 0,
		},
		{
			name: "mixed_zero_price_and_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 99.99},
				{ProductID: 2, Quantity: 4, Price: 0},
				{ProductID: 3, Quantity: 2, Price: 12.5},
			},
			// 0*99.99 + 4*0 + 2*12.5 = 25
			wantTotal: 25,
			precision: 0,
		},
		{
			name: "negative_price_and_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: -2, Price: 10},
				{ProductID: 2, Quantity: 3, Price: -5},
			},
			// (-2)*10 + 3*(-5) = -20 -15 = -35
			wantTotal: -35,
			precision: 0,
		},
		{
			name: "very_large_price_causes_inf",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: math.MaxFloat64},
			},
			// 2*MaxFloat64 overflows → +Inf
			wantIsInf: true,
		},
		{
			name: "price_is_nan",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
				{ProductID: 2, Quantity: 2, Price: 10},
			},
			// NaN propagates through the sum
			wantIsNaN: true,
		},
		{
			name: "quantity_is_max_int",
			items: []OrderItem{
				{ProductID: 1, Quantity: math.MaxInt32, Price: 1.23},
			},
			// проверяем, что арифметика не ломается при большом Quantity
			wantTotal: float64(math.MaxInt32) * 1.23,
			precision: 0,
		},
		{
			name: "precision_edge_0.1",
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, Price: 0.1},
				{ProductID: 2, Quantity: 7, Price: 0.2},
			},
			// 3*0.1 + 7*0.2 = 0.3 + 1.4 = 1.7 (может быть небольшая погрешность)
			wantTotal: 1.7,
			precision: 1e-9,
		},
	}

	for _, tc := range cases {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()

			o := &Order{
				Items: tc.items,
			}
			o.CalculateTotal()

			if tc.wantIsNaN {
				if !math.IsNaN(o.Total) {
					t.Fatalf("expected Total to be NaN, got %v", o.Total)
				}
				return
			}
			if tc.wantIsInf {
				if !math.IsInf(o.Total, 1) {
					t.Fatalf("expected Total to be +Inf, got %v", o.Total)
				}
				return
			}
			if tc.precision == 0 {
				if o.Total != tc.wantTotal {
					t.Fatalf("expected Total %v, got %v", tc.wantTotal, o.Total)
				}
			} else {
				if math.Abs(o.Total-tc.wantTotal) > tc.precision {
					t.Fatalf("expected Total ≈ %v (±%v), got %v", tc.wantTotal, tc.precision, o.Total)
				}
			}
		})
	}
}
```

### Что покрывает тест

| Edge‑case | Почему он новый (не дублирует существующие) |
|-----------|----------------------------------------------|
| `zero_quantity` | Проверяется, что элементы с `Quantity == 0` не влияют на сумму (в оригинальных тестах только пустой/`nil` срез). |
| `zero_price` | Суммируются элементы с н

**File:** `api/api_order_test.go`  
**Package:** `api` (the same package that already contains the other API‑handler tests)  

```go
// api/api_order_test.go
package api

import (
	"net/http"
	"testing"

	"github.com/go-chi/chi/v5"
	"github.com/stretchr/testify/assert"
)

// TestAPIOrderFullFlow creates a category, a product inside that category,
// places an order for the product, then runs the *process* and *complete*
// actions.  All steps are exercised through the public HTTP API, exactly the
// way the integration tests do it now, but this single test glues the whole
// happy‑path together.
//
// Naming follows the project convention: TestAPI<Layer><Feature>.
// The test lives in the *handler* layer (API) and therefore starts with
// “TestAPI”.  The “FullFlow” suffix makes it clear that it is a end‑to‑end
// scenario that touches several layers (category → product → order → use‑case
// → repository → entity).
func TestAPIOrderFullFlow_CreateCategoryProductOrderProcessComplete(t *testing.T) {
	// --------------------------------------------------------------------
	// 1️⃣  Set up a fresh in‑memory SQLite server with the full handler stack.
	// --------------------------------------------------------------------
	srv := setupTestServer(t) // defined in testhelper_test.go
	defer srv.Close()

	// --------------------------------------------------------------------
	// 2️⃣  Helper: create a category (POST /categories)
	// --------------------------------------------------------------------
	catPayload := map[string]any{
		"name": "Кофе",          // required
		"slug": "coffee",        // required
		"description": "Все виды кофе",
	}
	catResp := postJSON(t, srv.URL+"/categories", catPayload)
	assert.Equal(t, http.StatusCreated, catResp.Code)

	var catResult struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, catResp.Body, &catResult)

	// --------------------------------------------------------------------
	// 3️⃣  Helper: create a product that belongs to the category we just made.
	// --------------------------------------------------------------------
	prodPayload := map[string]any{
		"name":        "Латте",
		"category_id": catResult.ID,
		"price":       350.0,
		"description": "Молочный кофе",
		"image_url":   "https://example.com/latte.png",
		"in_stock":    true,
	}
	prodResp := postJSON(t, srv.URL+"/products", prodPayload)
	assert.Equal(t, http.StatusCreated, prodResp.Code)

	var prodResult struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, prodResp.Body, &prodResult)

	// --------------------------------------------------------------------
	// 4️⃣  Create an order that contains the product we just created.
	// --------------------------------------------------------------------
	orderPayload := map[string]any{
		"customer_id": "alice@example.com",
		"items": []any{
			map[string]any{
				"product_id": prodResult.ID,
				"quantity":   2,
			},
		},
	}
	orderResp := postJSON(t, srv.URL+"/orders", orderPayload)
	assert.Equal(t, http.StatusCreated, orderResp.Code)

	var orderResult struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, orderResp.Body, &orderResult)

	// --------------------------------------------------------------------
	// 5️⃣  Process the order (POST /orders/{id}/process)
	// --------------------------------------------------------------------
	processResp := doPost(t, srv.URL+"/orders/"+itoa(orderResult.ID)+"/process")
	assert.Equal(t, http.StatusOK, processResp.Code)

	// Verify that the status really changed to *processing*.
	getAfterProcess := doGet(t, srv.URL+"/orders/"+itoa(orderResult.ID))
	var orderAfterProcess struct {
		Status string `json:"status"`
	}
	decodeBody(t, getAfterProcess.Body, &orderAfterProcess)
	assert.Equal(t, "processing", orderAfterProcess.Status)

	// --------------------------------------------------------------------
	// 6️⃣  Complete the order (POST /orders/{id}/complete)
	// --------------------------------------------------------------------
	completeResp := doPost(t, srv.URL+"/orders/"+itoa(orderResult.ID)+"/complete")
	assert.Equal(t, http.StatusOK, completeResp.Code)

	// Verify final status is *completed*.
	getAfterComplete := doGet(t, srv.URL+"/orders/"+itoa(orderResult.ID))
	var orderAfterComplete struct {
		Status string `json:"status"`
	}
	decodeBody(t, getAfterComplete.Body, &orderAfterComplete)
	assert.Equal(t, "completed", orderAfterComplete.Status)
}

/* -------------------------------------------------------------------------
   Helper utilities used only inside this test file.
   They are tiny wrappers around the generic helpers that already exist in
   testhelper_test.go (postJSON, doPost, doGet, decodeBody, itoa).
   Keeping them here makes the test self‑contained and easy to read.
   ------------------------------------------------------------------------- */

func itoa(i int64) string { return fmt.Sprintf("%d", i) }

// doPost sends an empty POST request (used for the /process, /complete,
// /cancel endpoints that do not expect a body).
func doPost(t *testing.T, url string) *httptest.ResponseRecorder {
	req, err := http.NewRequest(http.MethodPost, url, nil)
	assert.NoError(t, err)
	rr := httptest.NewRecorder()
	chi.NewRouter().ServeHTTP(rr, req) // the router is already attached to the server
	return rr
}

// doGet sends a GET request and returns the recorder.
func doGet(t *testing.T, url string) *httptest.ResponseRecorder {
	req, err := http.NewRequest(http.MethodGet, url, nil)
	assert.NoError(t, err)
	rr := httptest.NewRecorder()
	chi.NewRouter().ServeHTTP(rr, req)
	return rr
}
```

### What the test does, step‑by‑step

| Step | Action (HTTP) | Expected status | Why it matters |
|------|----------------|----------------|----------------|
| 1️⃣   | `POST /categories` | **201 Created** | Verifies the *Category* handler, repository and use‑case work together. |
| 2️⃣   | `POST /products`   | **201 Created** | Checks that a product can be created with a valid `category_id`. |
| 3️⃣   | `POST /orders`     | **201 Created** | The *Order* use‑case fetches the product price, fills `Item.Price`, and calls `CalculateTotal()`. |
| 4️⃣   | `POST /orders/{id}/process` | **200 OK** | Calls `OrderUseCase.Process`, which validates the current status (`new`) and updates it to `processing`. |
| 5️⃣   | `GET /orders/{id}` (after process) | **200 OK** | Confirms the status field is now `"processing"`. |
| 6️⃣   | `POST /orders/{id}/complete` | **200 OK** | Calls `OrderUseCase.Complete`, which only succeeds when the order is in `processing`. |
| 7️⃣   | `GET /orders/{id}` (after complete) | **200 OK** | Final verification that the status is `"completed"` – the whole state‑machine exercised. |

### Where the pieces live

| Layer | Package / File | Relevant function / method |
|-------|----------------|----------------------------|
| **Entity** | `entity/order.go` | `Validate()`, `CalculateTotal()`, `CanCancel()`, `CanComplete()` |
| **Repository** | `repository/sqlite/order.go` | `Create`, `GetByID`, `UpdateStatus`, `GetItems` |
| **Use‑case** | `usecase/order.go` | `Create`, `Process`, `Complete` |
| **Handler (API)** | `handler/order.go` | `CreateOrder`, `ProcessOrder`, `CompleteOrder`, `GetOrder` |
| **Test helpers** | `testhelper_test.go` | `setupTestServer`, `postJSON`, `decodeBody`, … |

All helpers (`setupTestServer`, `postJSON`, `decodeBody`) already exist in the project, so the test only adds the orchestration logic shown above. Running `go test ./...` will now execute this new end‑to‑end flow in addition to the existing 36 order‑API tests, bringing the total API‑handler test count to **37**.

**Кратко:**  
Сейчас у проекта ≈ 600 тестов, из них ≈ 94 интеграционных (SQLite) и ≈ 237 юнит‑тестов сущностей. Большая часть тестов уже написана в виде table‑driven‑subtests, но есть несколько «узких мест», которые дают лишний накладной расход и иногда приводят к флейкам. Ниже — конкретный план оптимизации, разбитый по уровням, с примерами кода и указанием файлов/имен тестов, к которым он относится.

