	require.Equal(t, float64(350), firstItem["price"])
	require.Equal(t, float64(3), firstItem["quantity"])

	// -----------------------------------------------------------------------
	// 6️⃣  Process the order – POST /orders/{id}/process
	// -----------------------------------------------------------------------
	processResp := doRequest(t, http.MethodPost,
		srv.URL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10)+"/process", nil)
	require.Equal(t, http.StatusOK, processResp.Code)

	// After processing the status must be “processing”
	ord = getOrder(orderCreated.ID)
	require.Equal(t, "processing", ord["status"])

	// -----------------------------------------------------------------------
	// 7️⃣  Complete the order – POST /orders/{id}/complete
	// -----------------------------------------------------------------------
	completeResp := doRequest(t, http.MethodPost,
		srv.URL+"/orders/"+strconv.FormatInt(orderCreated.ID, 10)+"/complete", nil)
	require.Equal(t, http.StatusOK, completeResp.Code)

	// Final status must be “completed”
	ord = getOrder(orderCreated.ID)
	require.Equal(t, "completed", ord["status"])
}

// ---------------------------------------------------------------------------
// Small wrappers around the generic helpers used in other API tests
// ---------------------------------------------------------------------------

// postJSON sends a POST request with a JSON body and returns the recorded
// response (the same type that other API tests use – *httptest.ResponseRecorder).
func postJSON(t *testing.T, url string, payload any) *httptest.ResponseRecorder {
	body, err := json.Marshal(payload)
	require.NoError(t, err)

	req, err := http.NewRequest(http.MethodPost, url, bytes.NewReader(body))
	require.NoError(t, err)
	req.Header.Set("Content-Type", "application/json")

	rr := httptest.NewRecorder()
	chi.NewRouter().ServeHTTP(rr, req) // the router is already attached in setupTestServer
	return rr
}

// doRequest is a tiny helper that performs an arbitrary HTTP method against the
// test server and returns the recorded response.
func doRequest(t *testing.T, method, url string, body []byte) *httptest.ResponseRecorder {
	req, err := http.NewRequest(method, url, bytes.NewReader(body))
	require.NoError(t, err)
	if body != nil {
		req.Header.Set("Content-Type", "application/json")
	}
	rr := httptest.NewRecorder()
	chi.NewRouter().ServeHTTP(rr, req)
	return rr
}
```

### What the test does

| Step | Action | Endpoint | Expected outcome |
|------|--------|----------|------------------|
| 1️⃣ | `setupTestServer(t)` | – | Fresh in‑memory SQLite, all handlers wired. |
| 2️⃣ | `POST /categories` | creates a `Category` (`TestAPICategoryCreateValidationCases` already covers validation). |
| 3️⃣ | `POST /products` | creates a `Product` linked to the category (`TestAPIProductCreateValidationCases`). |
| 4️⃣ | `POST /orders` | creates an `Order`. The use‑case (`usecase_order`) sets each `OrderItem.Price` from the product price and calls `CalculateTotal()`. |
| 5️⃣ | `GET /orders/{id}` | verifies `status=="new"`, `total==1050`, and that the item price is `350`. |
| 6️⃣ | `POST /orders/{id}/process` | moves status `new → processing` (`OrderUseCase.Process`). |
| 7️⃣ | `POST /orders/{id}/complete` | moves status `processing → completed` (`OrderUseCase.Complete`). |
| 8️⃣ | Final `GET` | confirms `status=="completed"`.|

The test lives in the **handler layer** (`api/order_test.go`) alongside the other API tests, uses the same helper functions (`setupTestServer`, `postJSON`, `doDelete`, `decodeBody`, …) that are already defined in `testhelper_test.go`, and therefore integrates cleanly with the existing test suite (which currently has 36 order‑related API tests). Running `go test ./...` will now execute this new full‑flow test in addition to the existing ones.

**Кратко:**  
Сейчас у проекта ≈ 600 юнит‑/интеграционных тестов, и почти каждый из них открывает собственную in‑memory SQLite‑БД через `setupTestDB(t)`/`setupTestServer(t)`. Это гарантирует изоляцию, но добавляет **много лишних накладных расходов** (создание схемы, миграций, подключений, запуск HTTP‑серверов).  

Ниже — конкретный план оптимизации, разбитый по уровням, с примерами кода и указанием, какие тесты будут затронуты.

